-- ==========================================
-- MENU TABLES AND DATA
-- ==========================================

-- Table: pizza_categories
CREATE TABLE IF NOT EXISTS pizza_categories (
  id text PRIMARY KEY,
  name text NOT NULL,
  name_th text,
  icon text,
  created_at timestamptz DEFAULT now() NOT NULL
);

-- Table: pizza_items
CREATE TABLE IF NOT EXISTS pizza_items (
  id text PRIMARY KEY,
  category_id text REFERENCES pizza_categories(id) ON DELETE CASCADE NOT NULL,
  name text NOT NULL,
  name_th text,
  description text NOT NULL DEFAULT '',
  description_th text NOT NULL DEFAULT '',
  price numeric(10,2) NOT NULL DEFAULT 0,
  image_url text NOT NULL DEFAULT '',
  image_file text NOT NULL DEFAULT '',
  sku text NOT NULL DEFAULT '',
  allowed_extras_group text NOT NULL DEFAULT '',
  created_at timestamptz DEFAULT now() NOT NULL
);

-- Table: pizza_variants
CREATE TABLE IF NOT EXISTS pizza_variants (
  id text PRIMARY KEY,
  item_id text REFERENCES pizza_items(id) ON DELETE CASCADE NOT NULL,
  name text NOT NULL,
  name_th text,
  sku text NOT NULL DEFAULT '',
  price numeric(10,2) NOT NULL DEFAULT 0,
  price_modifier numeric(10,2) NOT NULL DEFAULT 0,
  created_at timestamptz DEFAULT now() NOT NULL
);

-- Table: pizza_extras
CREATE TABLE IF NOT EXISTS pizza_extras (
  id text PRIMARY KEY,
  group_name text NOT NULL,
  name text NOT NULL,
  name_th text,
  sku text NOT NULL DEFAULT '',
  price numeric(10,2) NOT NULL DEFAULT 0,
  created_at timestamptz DEFAULT now() NOT NULL
);

-- RLS Configuration
ALTER TABLE pizza_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE pizza_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE pizza_variants ENABLE ROW LEVEL SECURITY;
ALTER TABLE pizza_extras ENABLE ROW LEVEL SECURITY;

-- Select Policies (Public read access)
CREATE POLICY "Public can read pizza categories" ON pizza_categories FOR SELECT TO public USING (true);
CREATE POLICY "Public can read pizza items" ON pizza_items FOR SELECT TO public USING (true);
CREATE POLICY "Public can read pizza variants" ON pizza_variants FOR SELECT TO public USING (true);
CREATE POLICY "Public can read pizza extras" ON pizza_extras FOR SELECT TO public USING (true);

-- Admin Write Policies (Authenticated users)
CREATE POLICY "Admins can modify pizza categories" ON pizza_categories FOR ALL TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Admins can modify pizza items" ON pizza_items FOR ALL TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Admins can modify pizza variants" ON pizza_variants FOR ALL TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Admins can modify pizza extras" ON pizza_extras FOR ALL TO authenticated USING (true) WITH CHECK (true);

